-- ============================================================
-- Festival metadata enrichment for the DJ Mag Top 100 imports.
-- Curated city / genres / one-line description / official site.
-- Idempotent and non-destructive: only fills missing fields
-- (existing descriptions, websites and non-empty genre arrays
-- are preserved). Unknown fields stay null.
-- ============================================================

update public.festivals f
set
  city = coalesce(f.city, d.city),
  genres = case when cardinality(f.genres) = 0 and d.genres is not null then d.genres else f.genres end,
  description = coalesce(f.description, d.description),
  official_website = coalesce(f.official_website, d.website)
from (values
