-- Holy Ship! Wrecked actually takes place in the Dominican Republic
-- (organizer is US-based, which is why DJ Mag lists it as USA).
update public.festivals
set country = 'DO', city = 'Punta Cana'
where slug = 'holy-ship-wrecked';
